struct PromoLinkPayload: Equatable {
    let code: String
    let discount: Int
}

struct AppliedPromo: Identifiable, Equatable {
    let id = UUID()
    let code: String
    let discount: Int
    let appliedToUserID: String
    let appliedAt: Date
}

final class PromoManager: ObservableObject {
    static let shared = PromoManager()
    @Published var lastAppliedPromo: AppliedPromo?

    private init() {}

    func applyPromo(_ promo: PromoLinkPayload, to userID: String = UserSession.current.userID) {
        let applied = AppliedPromo(
            code: promo.code,
            discount: promo.discount,
            appliedToUserID: userID,
            appliedAt: Date()
        )
        lastAppliedPromo = applied
        UserAccountStore.shared.applyPromo(applied, to: userID)
    }
}

final class PromoRouter {
    static let shared = PromoRouter()

    private init() {}

    func handle(url: URL) {
        guard let promo = PromoURLParser.parse(url: url) else { return }
        PromoManager.shared.applyPromo(promo)
    }
}

enum PromoURLParser {
    static func parse(url: URL) -> PromoLinkPayload? {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: false),
              let host = components.host,
              host == "myapp.com",
              components.path == "/promo" else {
            return nil
        }

        let items = components.queryItems ?? []
        guard let code = items.first(where: { $0.name == "code" })?.value,
              !code.isEmpty,
              let discountString = items.first(where: { $0.name == "discount" })?.value,
              let discount = Int(discountString),
              (0...100).contains(discount) else {
            return nil
        }

        return PromoLinkPayload(code: code, discount: discount)
    }
}

final class UserSession {
    static let current = UserSession()
    let userID: String = "user_12345"
}

final class UserAccountStore {
    static let shared = UserAccountStore()
    private var appliedPromos: [String: [AppliedPromo]] = [:]

    private init() {}

    func applyPromo(_ promo: AppliedPromo, to userID: String) {
        appliedPromos[userID, default: []].append(promo)
    }

    func promos(for userID: String) -> [AppliedPromo] {
        appliedPromos[userID] ?? []
    }
}